INSERT INTO `m_blog` VALUES ('3', '1', '关注公众号JavaCat，回复xshell或navicat获取破解对应工具', '视频中所用到的xshell和navicat直接获取哈！', '### 工具获取\r\n\r\n* xshell 6 绿色破解版：关注公众号：JavaCat，回复 xshell 获取\r\n* Navicat 11 简体中文版：关注公众号：JavaCat，回复 navicat 获取\r\n\r\n公众号二维码：\r\n\r\n![JavaCat](//image-1300566513.cos.ap-guangzhou.myqcloud.com/upload/images/20201020/7fa16a1f957f4cfebe7be1f6675f6f36.png \"JavaCat\")\r\n\r\n直接扫码回复对应关键字\r\n\r\n**推荐阅读：**\r\n\r\n[B站86K播放量，SpringBoot+Vue前后端分离完整入门教程！](https://mp.weixin.qq.com/s/jGEkHTf2X8l-wUenc-PpEw)\r\n\r\n[分享一套SpringBoot开发博客系统源码，以及完整开发文档！速度保存！](https://mp.weixin.qq.com/s/jz6e977xP-OyaAKNjNca8w)\r\n\r\n[Github上最值得学习的100个Java开源项目，涵盖各种技术栈！](https://mp.weixin.qq.com/s/N-U0TaEUXnBFfBsmt_OESQ)\r\n\r\n[2020年最新的常问企业面试题大全以及答案](https://mp.weixin.qq.com/s/lR5LC5GnD2Gs59ecV5R0XA)', '2021-11-26 15:45:45', '0', '0', '0', '0', '1');
INSERT INTO `m_blog` VALUES ('7', '1', '你真的会写单例模式吗?', '单例模式可能是代码最少的模式了，但是少不一定意味着简单，想要用好、用对单例模式，还真得费一番脑筋。本文对 Java 中常见的单例模式写法做了一个总结，如有错漏之处，恳请读者指正。', '> 作者：吃桔子的攻城狮 来源：http://www.tekbroaden.com/singleton-java.html\n\n\n单例模式可能是代码最少的模式了，但是少不一定意味着简单，想要用好、用对单例模式，还真得费一番脑筋。本文对 Java 中常见的单例模式写法做了一个总结，如有错漏之处，恳请读者指正。\n\n饿汉法\n===\n\n顾名思义，饿汉法就是在第一次引用该类的时候就创建对象实例，而不管实际是否需要创建。代码如下：\n\n```\npublic class Singleton {  \n    private static Singleton = new Singleton();\n    private Singleton() {}\n    public static getSignleton(){\n        return singleton;\n    }\n}\n\n```\n\n这样做的好处是编写简单，但是无法做到延迟创建对象。但是我们很多时候都希望对象可以尽可能地延迟加载，从而减小负载，所以就需要下面的懒汉法：\n', '2021-11-26 15:45:51', '0', '0', '0', '0', '1');
INSERT INTO `m_blog` VALUES ('9', '1', '真正理解Mysql的四种隔离级别@', '事务是应用程序中一系列严密的操作，所有操作必须成功完成，否则在每个操作中所作的所有更改都会被撤消。也就是事务具有原子性，一个事务中的一系列的操作要么全部成功，要么一个都不做。\n\n事务的结束有两种，当事务中的所以步骤全部成功执行时，事务提交。如果其中一个步骤失败，将发生回滚操作，撤消撤消之前到事务开始时的所以操作。', '### 什么是事务  \n\n> 事务是应用程序中一系列严密的操作，所有操作必须成功完成，否则在每个操作中所作的所有更改都会被撤消。也就是事务具有原子性，一个事务中的一系列的操作要么全部成功，要么一个都不做。\n> \n> 事务的结束有两种，当事务中的所以步骤全部成功执行时，事务提交。如果其中一个步骤失败，将发生回滚操作，撤消撤消之前到事务开始时的所以操作。\n\n**事务的 ACID**\n\n事务具有四个特征：原子性（ Atomicity ）、一致性（ Consistency ）、隔离性（ Isolation ）和持续性（ Durability ）。这四个特性简称为 ACID 特性。\n\n> 1 、原子性。事务是数据库的逻辑工作单位，事务中包含的各操作要么都做，要么都不做\n> \n> 2 、一致性。事 务执行的结果必须是使数据库从一个一致性状态变到另一个一致性状态。因此当数据库只包含成功事务提交的结果时，就说数据库处于一致性状态。如果数据库系统 运行中发生故障，有些事务尚未完成就被迫中断，这些未完成事务对数据库所做的修改有一部分已写入物理数据库，这时数据库就处于一种不正确的状态，或者说是 不一致的状态。', '2021-11-26 15:45:53', '0', '0', '0', '0', '1');
INSERT INTO `m_blog` VALUES ('32', '11', '快乐的篮球', '海沃德谈全队12人都有得分：这就是最快乐的篮球', '![lq.jpg](http://localhost:8081/files/20211127/ad46085e-42eb-4af8-9ec8-cb8a74908395_lq.jpg)\n\n直播吧11月27日讯 NBA常规赛，黄蜂在主场以133-115战胜森林狼。赛后，黄蜂球员海沃德接受了采访。\n\n当谈到本场比赛时，海沃德说道：“当每一个人都参与其中时，这就是最快乐的篮球。每个人都可以得分，每个人都能够在回合中碰到球，这样一场的比赛胜利意味着很多。”\n\n本场比赛，黄蜂队12人都获得上场机会，均有得分进账。其中，海沃德出场27分14秒，13投7中，得到18分6篮板6助攻3盖帽。', '2021-11-27 19:49:19', '0', '1', '0', '0', '2');
INSERT INTO `m_blog` VALUES ('53', '11', '上海媒体曝出争议猛料', '中国足球沦为大笑话,球迷骂声一片', '![641.jpg](http://localhost:8081/files/20211127/40c71ab3-5605-46e4-b4b4-aae77277feb4_641.jpg)\n\n\n**粗体**\n北京时间11月27日凌晨3点，中国足球传来最新消息，日前，针对中超的最新情况，上海媒体《东方体育日报》曝出争议猛料，他表示职业联盟可能会帮助确实有困难的球队，进入赛区内将包吃包住，而这样的操作却引来了很多球迷的质疑。《东方体育日报》这样写道：“中超联赛计划12月12日重燃战火，但目前多支球队陷入运营困难之中，广州队球员自发进行训练，河北队停止运营，一线队球员发声愿无偿工作，实际上，除了泰山、海港以及深足寥寥几队外，其他球队都或多或少存在问题。从《东方体育日报》的报道可以看出，为了确保中超能够照常重启，职业联盟将会对有困难的球队提供包吃包住的服务，虽然该媒体并没有透露更多的信息，但中超出现如此奇葩的操作，这不仅让中国足球沦为大笑话，而且还引来了很多球迷的一片骂声\n', '2021-11-27 20:52:25', '0', '2', '0', '0', '3');
INSERT INTO `m_blog` VALUES ('54', '11', 'Python的导图', '工作7年，我沉淀总结了11张从零学Python的导图', '![dada.jpg](http://localhost:8081/files/20211127/07d13958-459f-4f2e-b05a-99be71fe185d_dada.jpg)', '2021-11-27 19:53:10', '0', '0', '0', '0', '1');
INSERT INTO `m_blog` VALUES ('55', '11', '沃格尔不满遭13分逆转！', '湖人名宿表态：我想回家，这不是团队篮球', '![niuma.jpeg](http://localhost:8081/files/20211127/e76192d2-cef4-4289-ae21-4d39df50e63f_niuma.jpeg)\n\n\n137-141！湖人队在主场经过3加时苦战，最终以4分之差憾负于国王，无缘2连胜。这场比赛浓眉迎来复出，湖人3巨头再次合体，面对表现糟糕率先换帅的国王队，这本是湖人继续重塑信心的机会，然而，在第四节一度领先13分的大好局面下，湖人队再次出现拉胯，最终被对手拖进加时，而经过3次加时苦战之后，湖人这支老年队的体力明显不如对手，当福克斯在第三个加时还能够连续持球冲击篮筐时，此时的湖人似乎已经闻到了输球的气息。湖人新赛季组建了詹姆斯、浓眉和威少的3巨头组合，本来就备受争议，而经过21场比赛的实践之后，事实证明，外界的质疑并没有错。从威少赛季初的挣扎，到目前渐入佳境，湖人的战绩却一直起伏不定，不管3巨头表现是好是坏，湖人打任何对手都是五五开，完全没有一直想要争冠的球队应该有的气质。而这场比赛，湖人3巨头联手轰下了82分25篮板26助攻，但这样的表现依旧没能帮助他们赢下比赛，而且是赢下一支西部的鱼腩球队，让人失望至极。确实，湖人队拥有3名联盟顶级的球星，但他们在场上却没能打出1+1+1+大于等于3的效果，反而是3人在场上因为一些打法的冲突，让他们没能发挥出3人应有的实力。而在加时赛中，湖人队的球权基本上由詹姆斯和威少轮流掌控，并且大部分回合都是他们轮流单打，完全没能打出团队配合。赛季已经进行了4分之1，如果湖人不想让这个赛季就此浪费，他们显然需要在后面的比赛里找到更好的办法。而其中最为关键的人，就是沃格尔。沃格尔在赛后表示：“如果你在第四节领先对手13分，你就得赢下比赛”，可以看出，沃格尔对于最后遭到逆转也非常不满，但是，作为球队的主教练，他理应在对手追分的时候，找出好的办法，不管是阵容调整还是战术变化，都应该做出回应，避免球队在关键时刻浪费了巨大的优势，甚至一度还被反超险些熬不到加时。国王队已经因为战绩不佳而炒掉了主教练，而如果湖人队接下来还无法走出低迷，或许沃格尔这位关键教练的帅位，也不会太稳了。', '2021-11-30 00:23:20', '0', '1', '0', '2', '2');
INSERT INTO `m_blog` VALUES ('56', '11', '追梦谈克莱情绪激动', '追梦谈克莱情绪激动：我不知道有多少人像他那样热爱篮球', '![0ff41bd5ad6eddc4e9f8cb2a6036caf45366333e.jpeg](http://localhost:8081/files/20211127/8326ccd8-d6ab-4b47-8322-21702fb27807_0ff41bd5ad6eddc4e9f8cb2a6036caf45366333e.jpeg)\n\n\n直播吧11月27日讯 NBA常规赛，勇士主场118-103战胜开拓者迎来六连胜。\n\n赛后克莱一直呆呆地坐在替补席，并用毛巾将自己的头盖了起来。\n\n追梦在接受采访时也谈到了克莱赛后情绪激动一事，追梦表示：“我不知道有多少人像他那样热爱篮球。”\n\n“我可以表达我对他的爱，表达我的支持…看着他征服自己的（复出）旅程真是太棒了。”\n\n此役追梦出场34分18秒8投5中，三分球1中0、罚球3中2，拿到12分8篮板12助攻2抢断3盖帽。\n\n相关新闻：想什么呢？比赛结束20多分钟 克莱一直头盖毛巾坐在替补席', '2021-11-27 20:09:42', '0', '0', '0', '1', '2');
INSERT INTO `m_blog` VALUES ('57', '11', '中国男篮轻松击败日本队取得开门红', '篮球世界杯预选赛', '今天上午男篮世界杯预选赛中国对阵日本的比赛拉开帷幕，中国男篮这边主力尽出为的就是击败日本队拿到开门红，由于日本对这边归化球员加上八村塁这些主力球员没有回归，这样一来他们与中国队的实力存在很大的差距，最终四节比赛打完中国男篮以79-63击败日本队拿到开门红。\n![80cb39dbb6fd5266c235c9c525f3eb22d507363d.jpeg](http://localhost:8081/files/20211127/ecf9feb8-aa8f-417f-a62a-36066bbee1ab_80cb39dbb6fd5266c235c9c525f3eb22d507363d.jpeg)\n本场比赛作为中国男篮领军人物周琦和郭艾伦发挥超常，两人均砍下24分，带领男篮球员多次打出高光表现，尤其是周琦这边凭借出色的身高在比赛中展现出篮下的掌控力，全场17投11中拿到24分12篮板3盖帽的大号两双数据，不过周琦再比赛中也遭遇意外，在第三节他跳起来封盖对手上篮时，在落地后不慎崴脚，被搀扶着走出赛场，但愿周琦不会有打的伤病，毕竟中国男篮还得依靠他作为领头羊在世预赛上打出更好的成绩。\n![5bafa40f4bfbfbed577cf501fd1b8b3faec31f98.jpeg](http://localhost:8081/files/20211127/bf187469-def3-48d6-b9f7-c58e2ca9e07f_5bafa40f4bfbfbed577cf501fd1b8b3faec31f98.jpeg)\n本场比赛一上来周琦在篮下自投自抢拿到两分，紧接着郭艾伦突破得手再拿两分，在两人的带领下中国男篮在第一节打出一波19-2的进攻波直接打停日本队，在第一节比赛里郭艾伦和赵睿连续命中三分帮助中国队扩大分差，第一节打完中国队27-11领先对手16分。第二节回来日本队状态回暖双方在上半节你来我往，但是到下半节日本队逐渐有点扛不住，半场打完中国队45-29依然领先日本队16分。\n下半场开打周琦依然发挥他在篮下的优势，不断冲击内线，中国队开局又一次打出8-0的进攻小高潮，不曾想在接下来的比赛中周琦遭遇伤病，无奈退出比赛，好在中国队其他球员及时顶上第三节打完中国队以64-40将分差拉开到24分。最后一节日本队想趁着周琦受伤，中国队内线虚弱发起一波反扑，不过在郭艾伦的带领下中国队稳住场上局势，最终日本队提前放弃比赛中国队以79-63击败对手喜提开门红。\n中国队所处的小组有澳大利亚、日本和中国台湾，从实力上看澳大利亚显然要强于其他三支球队，毕竟他们拥有多名NBA球员，不过中国队晋级第二轮比赛还是比较容易的，接下来就看能不能顺利出线拿到世界杯的入场券。\n\n', '2021-11-27 19:59:40', '0', '1', '0', '0', '2');
INSERT INTO `m_blog` VALUES ('58', '1', '学会卤鹅能领1700元补贴？官方回应来了', '官方回应', '![466.jpg](http://localhost:8081/files/20211127/3825b743-71b6-4745-ab1f-58a602a541e3_466.jpg)\n\n学会卤鹅就能领1700元补贴？通过率高达97%？近日，深圳掀起了学做卤鹅、报名考试的热潮。11月25日，深圳市人力资源和社会保障局回应称系“误会”，因报名数据出现明显异常，已暂停潮式卤味制作专项职业能力考核报名。\n\n记者注意到，近日网络出现了关于深圳卤鹅考试的相关信息，称学潮式卤鹅政府补贴1700元，通过考试获得证书即可申请，考试通过率高达97%，还有网友附上“卤鹅宝典”，网友们纷纷表示“要去卤大鹅。”\n11月25日，深圳市人社局官微介绍，网上疯传的卤鹅考试，学名为“潮式卤味”制作专项职业能力考核，实际上是技能人才评价的一种方式，其他方式还包括职业资格鉴定、职业技能等级认定。\n\n其中，职业资格鉴定、职业技能等级认定是综合性的评价方式，评价结果从初级工到高级技师共分为5个等级，而专项职业能力是就业的最小技能单元，也是技能类职业的基础组成部分，考核结果不分等级，由各地人力资源保障部门核发证书。', '2021-12-17 19:30:56', '0', '1', '0', '3', '4');
INSERT INTO `m_blog` VALUES ('59', '1', 'HKA官宣', 'HKA官宣：由于近两年的投资和补助大幅减少我们将解散LOL分部 ', '![d47804bcd6504fe084519fc5f3f05e3e.jpeg](http://localhost:8081/files/20211127/9e112503-0702-48ba-80e7-a0fafaff8daa_d47804bcd6504fe084519fc5f3f05e3e.jpeg)\n\n\nPCS赛区HKA俱乐部官宣俱乐部将正式解散LOL分部：\n\n敬爱的英雄联盟粉丝们，令人遗憾的，在此沉重宣布以下消息，自退出LMS后，除钟老板自行出资以外，投资人与相关赛事补助大幅减少，经过投资人与后勤团队共同讨论后决议，目前暂时停止英雄联盟职业战队与暂时不参与PCS相关比赛，此刻有许多美好回忆与满满的不舍，我们很感谢多年来所有HKA英雄联盟粉丝的支持，不排除未来有任何机会，HKA会再次复出参与比赛。', '2021-11-27 20:03:41', '0', '0', '0', '0', '5');
INSERT INTO `m_blog` VALUES ('60', '1', '美丽景色', '闲时拍的景色', '![bg.jpg](http://localhost:8081/files/20211127/4041f9a6-b86b-41e8-abff-5479a6bfc421_bg.jpg)![1618506678836.jpg](http://localhost:8081/files/20211127/ee00423e-41dc-43cc-80a4-5396d171666b_1618506678836.jpg)', '2021-11-27 20:04:54', '0', '0', '0', '0', '5');
